mapper.select:
SELECT pp.id, pp.prob_id AS probId, pp.product_code AS productCode, pp.product_name AS productName, pp.product_model AS productModel, pp.status, pp.create_time AS createTime, pp.create_by AS createBy, m.probNum, m.theme FROM prob_product pp LEFT JOIN prob_main m ON pp.prob_id = m.id WHERE 1=1
AND pp.prob_id = #{params.probId}
AND pp.product_code LIKE CONCAT('%', #{params.productCode}, '%')
AND pp.product_name LIKE CONCAT('%', #{params.productName}, '%')
AND pp.status = #{params.status}
ORDER BY pp.create_time DESC
LIMIT #{params.offset}, #{params.pageSize}
